// Compare this week vs last week
const thisWeek = items[0].json.rows || [];
const lastWeek = items[1].json.rows || [];

// Create lookup for last week
const lastWeekMap = {};
lastWeek.forEach(row => {
  const page = row.keys[0];
  lastWeekMap[page] = row;
});

// Calculate changes
const pageAnalysis = thisWeek.map(row => {
  const page = row.keys[0];
  const previous = lastWeekMap[page] || { clicks: 0, impressions: 0, ctr: 0, position: 100 };

  const clicksChange = row.clicks - (previous.clicks || 0);
  const impressionsChange = row.impressions - (previous.impressions || 0);
  const ctrChange = (row.ctr - (previous.ctr || 0)) * 100; // Convert to percentage points
  const positionChange = (previous.position || 100) - row.position; // Positive = improved

  return {
    page: page.replace('https://iaml.com', ''),
    clicks: row.clicks,
    impressions: row.impressions,
    ctr: (row.ctr * 100).toFixed(2) + '%',
    position: row.position.toFixed(1),
    clicks_change: clicksChange,
    impressions_change: impressionsChange,
    ctr_change: ctrChange.toFixed(2),
    position_change: positionChange.toFixed(1),
    status: positionChange > 0 ? 'improved' : positionChange < 0 ? 'declined' : 'stable'
  };
});

// Find significant changes
const improved = pageAnalysis.filter(p => parseFloat(p.position_change) > 2);
const declined = pageAnalysis.filter(p => parseFloat(p.position_change) < -2);
const highImpressionLowCTR = pageAnalysis.filter(p => 
  p.impressions > 100 && parseFloat(p.ctr) < 2
);

// Summary stats
const totalClicks = thisWeek.reduce((sum, r) => sum + r.clicks, 0);
const totalImpressions = thisWeek.reduce((sum, r) => sum + r.impressions, 0);
const avgPosition = thisWeek.reduce((sum, r) => sum + r.position, 0) / thisWeek.length;

return [{
  json: {
    period: {
      start: $now.minus({days: 7}).toFormat('yyyy-MM-dd'),
      end: $now.minus({days: 1}).toFormat('yyyy-MM-dd')
    },
    summary: {
      total_clicks: totalClicks,
      total_impressions: totalImpressions,
      avg_position: avgPosition.toFixed(1),
      pages_analyzed: thisWeek.length
    },
    opportunities: {
      improved_pages: improved.length,
      declined_pages: declined.length,
      ctr_opportunities: highImpressionLowCTR.length
    },
    top_improved: improved.slice(0, 5),
    top_declined: declined.slice(0, 5),
    ctr_opportunities: highImpressionLowCTR.slice(0, 5),
    all_pages: pageAnalysis
  }
}];

